<?php if (!defined('ABSPATH')) exit; get_header(); $s = get_search_query(); ?>
<div class="flavor-container py-8"><h1 class="text-4xl font-bold mb-6">Búsqueda: "<?php echo esc_html($s); ?>"</h1><form method="get" class="mb-8 flex gap-2"><input type="text" name="s" value="<?php echo esc_attr($s); ?>" class="flex-1 px-4 py-3 border rounded-lg" autofocus/><button class="px-6 py-3 bg-primary text-white rounded-lg">Buscar</button></form><?php $q = new WP_Query(array('post_type' => 'evento', 's' => $s)); if ($q->have_posts()) : echo '<div class="grid md:grid-cols-3 gap-6">'; while ($q->have_posts()) : $q->the_post(); $fecha = get_post_meta(get_the_ID(), '_fecha_evento', true); $precio = get_post_meta(get_the_ID(), '_precio_entrada', true); echo '<article class="bg-white rounded-xl shadow-md overflow-hidden">'; if (has_post_thumbnail()) the_post_thumbnail('medium', array('class' => 'w-full aspect-video object-cover')); echo '<div class="p-5"><h2 class="text-xl font-bold mb-2"><a href="' . get_permalink() . '">' . get_the_title() . '</a></h2><p class="text-gray-600 mb-2">' . date_i18n('d/m/Y', strtotime($fecha)) . '</p><p class="text-lg font-bold text-primary">' . ($precio == '0' ? 'Gratis' : esc_html($precio) . '€') . '</p><a href="' . get_permalink() . '" class="mt-4 block text-center px-4 py-2 bg-primary text-white rounded-lg">Ver</a></div></article>'; endwhile; echo '</div>'; else : echo '<div class="text-center py-16"><h3 class="text-2xl font-bold">Sin resultados</h3></div>'; endif; wp_reset_postdata(); ?></div><?php get_footer(); ?>
